import { Component } from '@angular/core';

@Component({
    templateUrl: 'subnav.component.html',
    standalone: false
})
export class SubNavComponent {}
<div class="subnav-tabs mt-3 mb-4">
    <a routerLink="accounts" routerLinkActive="active" class="subnav-tab-item"><i class="bi bi-people"></i> Accounts</a>
    <a routerLink="employees" routerLinkActive="active" class="subnav-tab-item"><i class="bi bi-person-badge"></i> Employees</a>
    <a routerLink="departments" routerLinkActive="active" class="subnav-tab-item"><i class="bi bi-building"></i> Departments</a>
</div>
